import { loadContextFile } from './ContextLoader.js';
import { AgentRunner } from '../agent/AgentRunner.js';
import { DecisionStore } from '../decisions/DecisionStore.js';
import type { Decision } from '../decisions/types.js';
import type { Constraint } from '../constraints/types.js';

interface ContextBuildOptions {
  contextFilePath: string;
  systemPromptFile?: string | null;
  projectRoot?: string | null;
  blockConstraints?: Constraint[];
  warnConstraints?: Constraint[];
}

export interface ConsultationContext {
  profileName: string;
  systemPromptAppend?: string;
  decisions: Decision[];
}

const DEFAULT_SYSTEM_PROMPT = `You are EPAM CLI, an AI coding assistant running in the terminal. You have access to tools to read files, write files, search code, and execute commands. Be concise and helpful. When asked to perform tasks, prefer using tools over explaining what to do.`;
let pendingConsultation: ConsultationContext | null = null;

async function loadRelevantDecisions(projectRoot: string | null): Promise<Decision[]> {
  if (!projectRoot) {
    return [];
  }

  try {
    const store = new DecisionStore(projectRoot);
    const allDecisions = await store.list();

    // Return the 5 most recent decisions
    return allDecisions
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
      .slice(0, 5);
  } catch {
    // Gracefully handle missing or malformed decisions file
    return [];
  }
}

function formatDecisionsBlock(decisions: Decision[]): string {
  if (decisions.length === 0) {
    return '';
  }

  const lines = ['[DECISION RECORDS]', ''];

  for (const decision of decisions) {
    lines.push(`Decision ${decision.id}: ${decision.title}`);
    if (decision.description) {
      lines.push(`Description: ${decision.description}`);
    }
    lines.push(`Rationale: ${decision.rationale}`);
    lines.push(`Pattern to avoid: ${decision.pattern_to_avoid}`);
    lines.push(`Approved alternative: ${decision.approved_alternative}`);
    if (decision.tags.length > 0) {
      lines.push(`Tags: ${decision.tags.join(', ')}`);
    }
    lines.push('');
  }

  return lines.join('\n');
}

function formatBlockConstraints(constraints: Constraint[]): string {
  if (constraints.length === 0) {
    return '';
  }

  const lines = ['[CONSTRAINTS — MUST FOLLOW]', ''];

  for (const constraint of constraints) {
    lines.push(`- ${constraint.rule}`);
  }

  lines.push('');
  return lines.join('\n');
}

function formatWarnConstraints(constraints: Constraint[]): string {
  if (constraints.length === 0) {
    return '';
  }

  const lines = ['[ADVISORY CONSTRAINTS]', ''];

  for (const constraint of constraints) {
    lines.push(`- ${constraint.rule}`);
  }

  lines.push('');
  return lines.join('\n');
}

function formatConsultationDecision(decision: Decision): string[] {
  const lines = [`Decision ${decision.id}: ${decision.title}`];

  if (decision.description) {
    lines.push(`Description: ${decision.description}`);
  }

  lines.push(`Rationale: ${decision.rationale}`);
  lines.push(`Pattern to avoid: ${decision.pattern_to_avoid}`);
  lines.push(`Approved alternative: ${decision.approved_alternative}`);

  if (decision.tags.length > 0) {
    lines.push(`Tags: ${decision.tags.join(', ')}`);
  }

  return lines;
}

export function buildConsultationBlock(consultation: ConsultationContext): string {
  const lines = [`[CONSULTING: @${consultation.profileName}]`, ''];

  if (consultation.systemPromptAppend?.trim()) {
    lines.push(consultation.systemPromptAppend.trim(), '');
  }

  if (consultation.decisions.length > 0) {
    lines.push('[RECENT MATCHING DECISIONS]', '');

    for (const decision of consultation.decisions) {
      lines.push(...formatConsultationDecision(decision), '');
    }
  }

  return lines.join('\n').trimEnd();
}

export function prependConsultationToMessage(
  userMessage: string,
  consultation: ConsultationContext
): string {
  const block = buildConsultationBlock(consultation);
  return block ? `${block}\n\n${userMessage}` : userMessage;
}

export function queueConsultation(consultation: ConsultationContext): void {
  pendingConsultation = {
    ...consultation,
    systemPromptAppend: consultation.systemPromptAppend,
    decisions: [...consultation.decisions],
  };
}

export function setPendingConsultation(consultation: ConsultationContext): void {
  queueConsultation(consultation);
}

export function getPendingConsultation(): ConsultationContext | null {
  if (!pendingConsultation) {
    return null;
  }

  return {
    ...pendingConsultation,
    decisions: [...pendingConsultation.decisions],
  };
}

export function clearPendingConsultation(): void {
  pendingConsultation = null;
}

export function applyPendingConsultation(userMessage: string): string {
  if (!pendingConsultation) {
    return userMessage;
  }

  const consultation = pendingConsultation;
  pendingConsultation = null;
  return prependConsultationToMessage(userMessage, consultation);
}

export function consumeConsultationContext(userMessage: string): string {
  return applyPendingConsultation(userMessage);
}

let consultationPatchInstalled = false;

function installConsultationPatch(): void {
  if (consultationPatchInstalled) {
    return;
  }

  consultationPatchInstalled = true;

  const originalRun = AgentRunner.prototype.run;
  AgentRunner.prototype.run = async function patchedRun(this: AgentRunner): ReturnType<typeof originalRun> {
    const runner = this as unknown as { options: { userMessage: string } };
    runner.options.userMessage = applyPendingConsultation(runner.options.userMessage);
    return originalRun.apply(this);
  };
}

installConsultationPatch();

export async function buildSystemPrompt(opts: ContextBuildOptions): Promise<string> {
  const parts: string[] = [];

  // Base system prompt
  if (opts.systemPromptFile) {
    const custom = await loadContextFile(opts.systemPromptFile);
    if (custom) {
      parts.push(custom);
    } else {
      parts.push(DEFAULT_SYSTEM_PROMPT);
    }
  } else {
    parts.push(DEFAULT_SYSTEM_PROMPT);
  }

  // Block-severity constraints (injected prominently at the top)
  if (opts.blockConstraints && opts.blockConstraints.length > 0) {
    const blockConstraintsBlock = formatBlockConstraints(opts.blockConstraints);
    parts.push(`\n${blockConstraintsBlock}`);
  }

  // Decision records (injected early so they influence behavior)
  const decisions = await loadRelevantDecisions(opts.projectRoot ?? null);
  const decisionsBlock = formatDecisionsBlock(decisions);
  if (decisionsBlock) {
    parts.push(`\n${decisionsBlock}`);
  }

  // Project context
  const contextMd = await loadContextFile(opts.contextFilePath);
  if (contextMd) {
    parts.push(`\n## Project Context\n\n${contextMd}`);
  }

  if (opts.projectRoot) {
    parts.push(`\nWorking directory: ${opts.projectRoot}`);
  }

  // Warn-severity constraints (injected at the bottom as advisory notes)
  if (opts.warnConstraints && opts.warnConstraints.length > 0) {
    const warnConstraintsBlock = formatWarnConstraints(opts.warnConstraints);
    parts.push(`\n${warnConstraintsBlock}`);
  }

  return parts.join('\n');
}

import type { LLMProvider, Message } from '../providers/types.js';
import type { Tool } from '../tools/types.js';
import type {
  AuditorConfig,
  AuditorFinding,
  AuditorGateDecision,
  AuditorInput,
  AuditorResult,
  SeverityLevel,
} from './types.js';
import { SEVERITY_RANK } from './types.js';
import { AgentRunner } from '../agent/AgentRunner.js';
import { logger } from '../utils/logger.js';

/**
 * Executes a single persona-specific auditor against a proposed agent response.
 */
export class AuditorRunner {
  readonly name: string;

  constructor(
    readonly config: AuditorConfig,
    private provider: LLMProvider,
    private tools: Tool[],
  ) {
    this.name = config.name;
  }

  async run(input: AuditorInput): Promise<AuditorResult> {
    try {
      const runner = new AgentRunner({
        userMessage: this.buildAuditorUserPrompt(input),
        systemPrompt: this.buildAuditorSystemPrompt(),
        provider: this.provider,
        model: this.config.model,
        tools: this.tools,
        maxIterations: 5,
        dangerousSkipApproval: true,
      });

      const result = await runner.run();
      const findings = this.parseFindings(result.finalResponse);

      return {
        auditorName: this.config.name,
        findings,
        transcript: result.finalResponse,
        severity: this.getMaxSeverity(findings),
      };
    } catch (error) {
      logger.error({ error, auditor: this.config.name }, 'Auditor execution failed');
      return {
        auditorName: this.config.name,
        findings: [],
        transcript: `[ERROR] Auditor failed to execute: ${error instanceof Error ? error.message : String(error)}`,
        severity: 'info',
      };
    }
  }

  exceedsThreshold(result: AuditorResult): boolean {
    return (
      result.findings.length > 0 &&
      SEVERITY_RANK[result.severity] >= SEVERITY_RANK[this.config.severity_threshold]
    );
  }

  static evaluateGate(results: AuditorResult[], runners: AuditorRunner[]): AuditorGateDecision {
    const runnerByName = new Map(runners.map(runner => [runner.name, runner]));
    const blockingAuditors = results.filter(result => runnerByName.get(result.auditorName)?.exceedsThreshold(result));

    return {
      blocked: blockingAuditors.length > 0,
      blockingAuditors,
    };
  }

  private buildAuditorSystemPrompt(): string {
    return [
      `You are ${this.config.name}.`,
      `Persona: ${this.config.persona}`,
      `Primary focus: ${this.config.focus}`,
      '',
      'Audit the assistant response for issues that matter to your persona and focus area.',
      'You are reviewing a candidate answer before it is shown to the user.',
      'Consider correctness, safety, omissions, weak assumptions, and conflicts with the conversation context.',
      '',
      'Output one finding per line using exactly this format:',
      '[SEVERITY: info|warning|critical] <finding>',
      '',
      'If there are no issues, return:',
      '[SEVERITY: info] No findings.',
      '',
      'Be concise, concrete, and avoid generic advice.',
    ].join('\n');
  }

  private buildAuditorUserPrompt(input: AuditorInput): string {
    return [
      'Review this interaction before the answer is confirmed.',
      '',
      'User message:',
      input.userMessage,
      '',
      'Proposed assistant response:',
      input.proposedResponse,
      '',
      'Full conversation context:',
      this.formatConversationHistory(input.conversationHistory),
    ].join('\n');
  }

  private formatConversationHistory(history: Message[]): string {
    if (history.length === 0) {
      return '[no prior context]';
    }

    return history
      .map(message => {
        const role = message.role.toUpperCase();
        const content =
          typeof message.content === 'string'
            ? message.content
            : JSON.stringify(message.content);
        return `${role}: ${content}`;
      })
      .join('\n\n');
  }

  private parseFindings(transcript: string): AuditorFinding[] {
    const findings: AuditorFinding[] = [];

    for (const line of transcript.split('\n')) {
      const match = line.match(/\[SEVERITY:\s*(info|warning|critical)\]\s*(.+)/i);
      if (!match) {
        continue;
      }

      findings.push({
        auditorName: this.config.name,
        severity: match[1].toLowerCase() as SeverityLevel,
        finding: match[2].trim(),
      });
    }

    return findings;
  }

  private getMaxSeverity(findings: AuditorFinding[]): SeverityLevel {
    if (findings.some(finding => finding.severity === 'critical')) {
      return 'critical';
    }

    if (findings.some(finding => finding.severity === 'warning')) {
      return 'warning';
    }

    return 'info';
  }
}

import type { BackendClient } from '../http/BackendClient.js';
import { ConstraintsResponseSchema, type Constraint, type SeparatedConstraints } from './types.js';
import { logger } from '../utils/logger.js';

// Trust: constraint content originates from the EPAM platform backend; prompt injection defence is enforced at the infrastructure layer.

export class ConstraintLoader {
  private cache: Constraint[] | null = null;

  constructor(private readonly backendClient: BackendClient) {}

  /**
   * Fetches active constraints for a project from the backend.
   * Results are cached for the session duration.
   * If the endpoint is unreachable, returns empty array and logs warning.
   */
  async loadConstraints(projectId: string): Promise<Constraint[]> {
    // Return cached result if available
    if (this.cache !== null) {
      return this.cache;
    }

    try {
      const response = await this.backendClient.getProjectConstraints(projectId);

      // Validate response schema
      const parsed = ConstraintsResponseSchema.safeParse(response);
      if (!parsed.success) {
        logger.warn({ error: parsed.error }, 'Invalid constraints response schema');
        this.cache = [];
        return [];
      }

      // Filter out expired constraints
      const now = new Date();
      const activeConstraints = parsed.data.constraints.filter(constraint => {
        const expiresAt = new Date(constraint.expiresAt);
        return expiresAt > now;
      });

      this.cache = activeConstraints;
      return activeConstraints;
    } catch (error) {
      // Gracefully handle unreachable endpoint
      logger.warn({ error }, 'Failed to fetch project constraints, proceeding without constraints');
      this.cache = [];
      return [];
    }
  }

  /**
   * Separates constraints by severity for system prompt injection.
   */
  separateConstraintsBySeverity(constraints: Constraint[]): SeparatedConstraints {
    return {
      block: constraints.filter(c => c.severity === 'block'),
      warn: constraints.filter(c => c.severity === 'warn'),
    };
  }
}

