  private async reviewWithAuditors(
    finalResponse: string,
    messages: Message[],
  ): Promise<boolean> {
    if (this.options.onAuditorReview) {
      return this.options.onAuditorReview(
        this.options.userMessage,
        finalResponse,
        messages,
      );
    }

    const registry = AuditorRegistry.getActive();
    if (!registry || !registry.isEnabled()) {
      return true;
    }

    const runners = registry.getEnabledRunners(this.options.provider, this.options.tools);
    if (runners.length === 0) {
      return true;
    }

    logger.debug({ auditorCount: runners.length }, 'Running enabled auditors');

    const results = await Promise.all(
      runners.map(runner =>
        runner.run({
          userMessage: this.options.userMessage,
          proposedResponse: finalResponse,
          conversationHistory: messages,
        }),
      ),
    );

    await this.emitAuditorFindings(results);

    const gateDecision = AuditorRunner.evaluateGate(results, runners);
    if (!gateDecision.blocked) {
      return true;
    }

    return this.promptForAuditorGate(gateDecision.blockingAuditors);
  }

  private async emitAuditorFindings(results: AuditorResult[]): Promise<void> {
    const options = this.options as AuditorAwareAgentRunOptions;
    if (options.onAuditorFindings) {
      await options.onAuditorFindings(results);
      return;
    }

    for (const result of results) {
      if (result.findings.length === 0) {
        console.log(
          chalk.magenta(
            `[AUDITOR: ${result.auditorName}] Finding: ${result.transcript || 'No findings.'}`
          )
        );
        continue;
      }

      for (const finding of result.findings) {
        console.log(
          chalk.magenta(
            `[AUDITOR: ${result.auditorName}] Finding: (${finding.severity}) ${finding.finding}`
          )
        );
      }
    }
  }

  private async promptForAuditorGate(results: AuditorResult[]): Promise<boolean> {
    const options = this.options as AuditorAwareAgentRunOptions;
    if (options.onAuditorGate) {
      return options.onAuditorGate(results);
    }

    const blockingSummary = results
      .filter(result => result.findings.length > 0)
      .map(result => `${result.auditorName}:${result.severity}`)
      .join(', ');

    console.log(
      chalk.magenta(
        `Auditor gate triggered. Findings at or above threshold: ${blockingSummary}`
      )
    );

    const decision = await prompts({
      type: 'select',
      name: 'action',
      message: 'Proceed with the proposed response?',
      choices: [
        { title: 'Proceed', value: 'proceed' },
        { title: 'Reject', value: 'reject' },
      ],
      initial: 1,
    });

    return decision.action === 'proceed';
  }
}

