async function getProjectId(projectRoot: string): Promise<string> {
  // Use projectRoot path as a simple hash-based ID
  // In a real implementation, this might come from a settings file
  const hash = Buffer.from(projectRoot).toString('base64').replace(/[^a-zA-Z0-9]/g, '').slice(0, 16);
  return hash;
}

async function readContextFile(projectRoot: string): Promise<string> {
  const contextPath = path.join(projectRoot, '.epam', 'context.md');
