export function getSessionsDir(projectRoot: string | null): string {
  if (projectRoot) {
    return path.join(projectRoot, '.epam', 'sessions');
  }
  return path.join(getEpamGlobalDir(), 'sessions');
}

export function createSession(
  projectRoot: string | null,
  model: string,
  provider: string
): Session {
  return {
    id: ulid(),
    createdAt: Date.now(),
    updatedAt: Date.now(),
    projectRoot,
    model,
    provider,
    turns: [],
  };
}

export async function appendTurn(session: Session, turn: SessionTurn): Promise<void> {
  const sessionsDir = getSessionsDir(session.projectRoot);
  await ensureDir(sessionsDir);
  const filePath = path.join(sessionsDir, `${session.id}.jsonl`);
  session.turns.push(turn);
  session.updatedAt = Date.now();
  await appendLine(filePath, turn);
}

export async function appendBudgetEvent(
  session: Session,
  previousModel: string,
  newModel: string,
  costAtSwitch: number
): Promise<void> {
  const sessionsDir = getSessionsDir(session.projectRoot);
  await ensureDir(sessionsDir);
  const filePath = path.join(sessionsDir, `${session.id}.jsonl`);

  const event: BudgetEvent = {
    type: 'budget_downgrade',
    timestamp: Date.now(),
    previousModel,
    newModel,
    costAtSwitch,
  };

  session.updatedAt = Date.now();
  await appendLine(filePath, event);
}

export function createTurn(
  userMessage: string,
  assistantResponse: string,
  toolCallCount: number,
  usage: { inputTokens: number; outputTokens: number }
): SessionTurn {
  return {
    id: ulid(),
    timestamp: Date.now(),
    userMessage,
    assistantResponse,
    toolCallCount,
    usage,
  };
}

export async function loadSession(
  sessionId: string,
  projectRoot: string | null
): Promise<Session | null> {
  const sessionsDir = getSessionsDir(projectRoot);
  const filePath = path.join(sessionsDir, `${sessionId}.jsonl`);

  if (!(await pathExists(filePath))) {
    // Also check global sessions dir if not found locally
    const globalPath = path.join(getEpamGlobalDir(), 'sessions', `${sessionId}.jsonl`);
    if (!(await pathExists(globalPath))) return null;
    return loadSessionFile(globalPath, sessionId, null);
  }

  return loadSessionFile(filePath, sessionId, projectRoot);
}

async function loadSessionFile(
  filePath: string,
  sessionId: string,
  projectRoot: string | null
): Promise<Session> {
  const lines = await readLines(filePath);
  const turns: SessionTurn[] = lines
    .map(line => {
      try {
        return JSON.parse(line) as SessionTurn;
      } catch {
        return null;
      }
    })
    .filter((t): t is SessionTurn => t !== null);

  const stat = await fs.stat(filePath);

  return {
    id: sessionId,
    createdAt: stat.birthtimeMs,
    updatedAt: stat.mtimeMs,
    projectRoot,
    model: '',    // not stored in JSONL — caller fills in if needed
    provider: '',
    turns,
  };
}

export interface SessionSummary {
  id: string;
  updatedAt: Date;
  createdAt: Date;
  turnCount: number;
  path: string;
  model: string;
  totalInputTokens: number;
  totalOutputTokens: number;
  totalCost: number;
  client?: string;
  label?: string;
  originSessionId?: string;
  isFork?: boolean;
}

export async function listSessions(
  projectRoot: string | null,
  limit = 20
): Promise<SessionSummary[]> {
  const dirs = [getSessionsDir(projectRoot)];
  // Also include global sessions if project-local differs
  const globalDir = path.join(getEpamGlobalDir(), 'sessions');
  if (!dirs.includes(globalDir)) dirs.push(globalDir);

  const results: SessionSummary[] = [];

  for (const dir of dirs) {
    if (!(await pathExists(dir))) continue;
    const files = await fs.readdir(dir);
    for (const file of files.filter(f => f.endsWith('.jsonl'))) {
      const filePath = path.join(dir, file);
      try {
        const stat = await fs.stat(filePath);
        const lines = await readLines(filePath);
        const summary = await parseSessionSummary(
          file.replace('.jsonl', ''),
          filePath,
          lines,
          stat
        );
        results.push(summary);
      } catch (err) {
        // Warn but continue if a file is malformed
        console.warn(`Warning: Could not parse session file ${filePath}: ${err instanceof Error ? err.message : 'unknown error'}`);
      }
    }
  }

  return results
    .sort((a, b) => b.updatedAt.getTime() - a.updatedAt.getTime())
    .slice(0, limit);
}

async function parseSessionSummary(
  id: string,
  filePath: string,
  lines: string[],
  stat: Stats
): Promise<SessionSummary> {
  let model = 'unknown';
  let totalInputTokens = 0;
  let totalOutputTokens = 0;
  let client: string | undefined;
  let turnCount = 0;
  let label: string | undefined;
  let originSessionId: string | undefined;
  let isFork = false;

  for (const line of lines) {
    try {
      const entry = JSON.parse(line);

      // Check if it's a SessionTurn
      if (entry.usage && typeof entry.usage.inputTokens === 'number') {
        const turn = entry as SessionTurn;
        totalInputTokens += turn.usage.inputTokens;
        totalOutputTokens += typeof turn.usage.outputTokens === 'number' ? turn.usage.outputTokens : 0;
        turnCount++;
      }

      // Check if it's a BudgetEvent to track model
      if (entry.type === 'budget_downgrade' && entry.newModel) {
        model = entry.newModel;
      }

      // Check if it's a ForkMetadata event
      if (entry.type === 'fork_metadata') {
        const forkMeta = entry as ForkMetadata;
        isFork = true;
        label = forkMeta.label;
        originSessionId = forkMeta.originSessionId;
      }

      // Extract model from first turn if available (some sessions store it)
      if (!model || model === 'unknown') {
        if (entry.model && typeof entry.model === 'string') {
          model = entry.model;
        }
      }

      // Extract client metadata if present
      if (entry.client && typeof entry.client === 'string' && !client) {
        client = entry.client;
      }
    } catch {
      // Skip malformed lines
      continue;
    }
  }

  const totalCost = calculateCost(model, totalInputTokens, totalOutputTokens);

  return {
    id,
    updatedAt: stat.mtime,
    createdAt: new Date(stat.birthtimeMs),
    turnCount,
    path: filePath,
    model,
    totalInputTokens,
    totalOutputTokens,
    totalCost,
    client,
    label,
    originSessionId,
    isFork,
  };
}

