import os from 'os';
import path from 'path';

export type Platform = 'darwin' | 'linux' | 'win32';

export function getPlatform(): Platform {
  const p = process.platform;
  if (p === 'darwin' || p === 'linux' || p === 'win32') return p;
  return 'linux';
}

export function isWSL(): boolean {
  if (process.platform !== 'linux') return false;
  try {
    const release = os.release().toLowerCase();
    return release.includes('microsoft') || release.includes('wsl');
  } catch {
    return false;
  }
}

export function getHomeDir(): string {
  return os.homedir();
}

export function getEpamGlobalDir(): string {
  return path.join(getHomeDir(), '.epam');
}

export function getEpamProjectDir(projectRoot: string): string {
  return path.join(projectRoot, '.epam');
}

export function supportsKeytar(): boolean {
  return !isWSL() && getPlatform() !== 'linux';
}

export const IS_TTY = Boolean(process.stdout.isTTY);
export const IS_PIPE_MODE = !IS_TTY;

import fs from 'fs/promises';
import path from 'path';
import { createReadStream, createWriteStream } from 'fs';

export async function pathExists(filePath: string): Promise<boolean> {
  try {
    await fs.access(filePath);
    return true;
  } catch {
    return false;
  }
}

export async function ensureDir(dirPath: string): Promise<void> {
  await fs.mkdir(dirPath, { recursive: true });
}

export async function readJsonFile<T>(filePath: string): Promise<T | null> {
  try {
    const content = await fs.readFile(filePath, 'utf-8');
    return JSON.parse(content) as T;
  } catch {
    return null;
  }
}

export async function writeJsonFile(filePath: string, data: unknown): Promise<void> {
  await ensureDir(path.dirname(filePath));
  await fs.writeFile(filePath, JSON.stringify(data, null, 2), 'utf-8');
}

export async function appendLine(filePath: string, data: unknown): Promise<void> {
  await ensureDir(path.dirname(filePath));
  await fs.appendFile(filePath, JSON.stringify(data) + '\n', 'utf-8');
}

export async function readLines(filePath: string): Promise<string[]> {
  try {
    const content = await fs.readFile(filePath, 'utf-8');
    return content.split('\n').filter((line) => line.trim());
  } catch {
    return [];
  }
}

export async function findAncestorFile(
  startDir: string,
  filename: string
): Promise<string | null> {
  let current = path.resolve(startDir);
  const root = path.parse(current).root;

  while (current !== root) {
    const candidate = path.join(current, filename);
    if (await pathExists(candidate)) {
      return candidate;
    }
    current = path.dirname(current);
  }
  return null;
}

