class SingleResponseProvider implements LLMProvider {
  readonly name = 'test';
  readonly defaultModel = 'test';

  constructor(private response: ProviderResponse) {}

  async complete(_r: ProviderRequest): Promise<ProviderResponse> {
    return this.response;
  }

  async stream(_r: ProviderRequest, handler: StreamHandler): Promise<ProviderResponse> {
    const text = this.response.content.find(p => p.type === 'text')?.text ?? '';
    if (text) handler({ type: 'text_delta', text });
    handler({ type: 'message_stop', stopReason: this.response.stopReason });
    return this.response;
  }
}

describe('AgentRunner conversation continuity', () => {
  it('prepends history messages before the current user message', async () => {
    let capturedMessages: unknown = null;

    const provider: LLMProvider = {
      name: 'spy',
      defaultModel: 'spy',
      async complete() { throw new Error('unused'); },
      async stream(request, handler) {
        capturedMessages = [...request.messages];
        const res: ProviderResponse = {
          content: [{ type: 'text', text: 'reply' }],
          stopReason: 'end_turn',
          usage: { inputTokens: 1, outputTokens: 1 },
        };
        handler({ type: 'text_delta', text: 'reply' });
        handler({ type: 'message_stop', stopReason: 'end_turn' });
        return res;
      },
    };

    const runner = new AgentRunner({
      userMessage: 'follow-up question',
      systemPrompt: 'sys',
      provider,
      model: 'spy',
      tools: [],
      history: [
        { role: 'user', content: 'first question' },
        { role: 'assistant', content: 'first answer' },
      ],
    });

    await runner.run();

    const msgs = capturedMessages as Array<{ role: string; content: unknown }>;
    expect(msgs).toHaveLength(3);
    expect(msgs[0].role).toBe('user');
    expect(msgs[0].content).toBe('first question');
    expect(msgs[1].role).toBe('assistant');
    expect(msgs[1].content).toBe('first answer');
    expect(msgs[2].role).toBe('user');
    expect(msgs[2].content).toBe('follow-up question');
  });

  it('returns the full messages array in result', async () => {
    const provider = new SingleResponseProvider({
      content: [{ type: 'text', text: 'hello back' }],
      stopReason: 'end_turn',
      usage: { inputTokens: 1, outputTokens: 1 },
    });

    const runner = new AgentRunner({
      userMessage: 'hello',
      systemPrompt: '',
      provider,
      model: 'test',
      tools: [],
      history: [
        { role: 'user', content: 'prior' },
        { role: 'assistant', content: 'prior reply' },
      ],
    });

    const result = await runner.run();
    expect(result.messages).toHaveLength(4);
    expect(result.messages[0].content).toBe('prior');
    expect(result.messages[1].content).toBe('prior reply');
    expect(result.messages[2].content).toBe('hello');
    // Last message is assistant with ContentPart[]
    expect(result.messages[3].role).toBe('assistant');
  });

  it('works with no history (backward compatible)', async () => {
    const provider = new SingleResponseProvider({
      content: [{ type: 'text', text: 'answer' }],
      stopReason: 'end_turn',
      usage: { inputTokens: 1, outputTokens: 1 },
    });

    const runner = new AgentRunner({
      userMessage: 'question',
      systemPrompt: '',
      provider,
      model: 'test',
      tools: [],
    });

    const result = await runner.run();
    expect(result.messages).toHaveLength(2);
    expect(result.messages[0]).toEqual({ role: 'user', content: 'question' });
    expect(result.finalResponse).toBe('answer');
  });
});

import chalk from 'chalk';
import prompts from 'prompts';
import type { Message } from '../providers/types.js';
import type { ToolCallRequest } from '../tools/types.js';
import type { AgentRunOptions, AgentRunResult } from './types.js';
import type { AuditorResult } from '../auditors/types.js';
import { AuditorRegistry } from '../auditors/AuditorRegistry.js';
import { AuditorRunner } from '../auditors/AuditorRunner.js';
import { Executor } from './Executor.js';
import { compressHistory } from '../context/MemoryCompressor.js';
import { logger } from '../utils/logger.js';

const DEFAULT_MAX_TOOL_OUTPUT_CHARS = 32_768;
const DEFAULT_AUTO_COMPRESS_AT = 80_000;
const DEFAULT_MAX_OUTPUT_TOKENS = 16_384;

interface AuditorAwareAgentRunOptions extends AgentRunOptions {
  onAuditorFindings?: (results: AuditorResult[]) => void | Promise<void>;
  onAuditorGate?: (results: AuditorResult[]) => Promise<boolean>;
}

/**
 * AgentRunner executes the ReAct agent loop.
 *
 * Remote constraints should be loaded before session start and injected into the
 * system prompt via ContextBuilder. See ConstraintLoader for fetching constraints
 * from the backend at GET /v1/projects/{id}/constraints.
 */

function estimateTokens(messages: Message[]): number {
  let chars = 0;
  for (const m of messages) {
    if (typeof m.content === 'string') {
      chars += m.content.length;
    } else {
      chars += JSON.stringify(m.content).length;
    }
  }
  return Math.ceil(chars / 4);
}

function truncateToolOutput(content: string, limit: number): string {
  if (content.length <= limit) return content;
  const kept = content.slice(0, limit);
  const droppedChars = content.length - limit;
  return `${kept}\n\n[truncated — showing first ${limit.toLocaleString()} of ${content.length.toLocaleString()} chars (${droppedChars.toLocaleString()} dropped)]`;
}

export class AgentRunner {
  private executor: Executor;
  private iterationCount = 0;
  private totalInputTokens = 0;
  private totalOutputTokens = 0;
  private totalToolCalls = 0;
  private maxToolOutputChars: number;

  constructor(private options: AgentRunOptions) {
    this.executor = new Executor({
      tools: options.tools,
      dangerousSkipApproval: options.dangerousSkipApproval ?? false,
      maxConcurrency: 3,
    });
    this.maxToolOutputChars = options.maxToolOutputChars ?? DEFAULT_MAX_TOOL_OUTPUT_CHARS;
  }

  async run(): Promise<AgentRunResult> {
    const maxIterations = this.options.maxIterations ?? 20;
    const autoCompressAt = this.options.autoCompressAt ?? DEFAULT_AUTO_COMPRESS_AT;

    let messages: Message[] = [
      ...(this.options.history ?? []),
      { role: 'user', content: this.options.userMessage },
    ];

    let finalResponse = '';

    while (this.iterationCount < maxIterations) {
      this.iterationCount++;
      this.options.onIterationStart?.(this.iterationCount);

      logger.debug({ iteration: this.iterationCount }, 'Agent iteration');

      // Auto-compress if history has grown past threshold
      if (estimateTokens(messages) > autoCompressAt && messages.length > 6) {
        try {
          logger.debug('Auto-compressing conversation history');
          messages = await compressHistory(
            messages,
            this.options.provider,
            this.options.model,
          );
        } catch {
          logger.warn('Auto-compression failed, continuing with full history');
        }
      }

      let accumulatedText = '';

      const response = await this.options.provider.stream(
        {
          messages,
          systemPrompt: this.options.systemPrompt,
          tools: this.options.tools.map(t => t.definition),
          model: this.options.model,
          stream: true,
          maxTokens: this.options.maxOutputTokens ?? DEFAULT_MAX_OUTPUT_TOKENS,
        },
        delta => {
          if (delta.type === 'text_delta') {
            this.options.onTextDelta?.(delta.text);
            accumulatedText += delta.text;
          }
        }
      );

      this.totalInputTokens += response.usage.inputTokens;
      this.totalOutputTokens += response.usage.outputTokens;

      // Budget enforcement — check after every LLM response
      if (this.options.budgetGuard) {
        const check = this.options.budgetGuard.recordUsage(
          response.usage.inputTokens,
          response.usage.outputTokens,
        );
        if (check.action !== 'ok') {
          this.options.onBudgetCheck?.(check);
        }
        if (check.action === 'pause') {
          // Hard stop — append what we have and return immediately
          messages.push({ role: 'assistant', content: response.content });
          return this.buildResult(
            response.content.filter(p => p.type === 'text').map(p => p.text ?? '').join('') || check.message,
            messages,
          );
        }
      }

      const toolUses = response.content.filter(p => p.type === 'tool_use');
      const textParts = response.content.filter(p => p.type === 'text');

      if (textParts.length > 0 || accumulatedText) {
        finalResponse = textParts.map(p => p.text ?? '').join('') || accumulatedText;
      }

      if (response.stopReason === 'end_turn' || toolUses.length === 0) {
        // Append the final assistant message so messages array is complete
        messages.push({ role: 'assistant', content: response.content });

        if (finalResponse) {
          const shouldProceed = await this.reviewWithAuditors(finalResponse, messages);
          if (!shouldProceed) {
            return this.buildResult('[Response blocked by auditor review]', messages);
          }
        }

        break;
      }

      if (response.stopReason === 'max_tokens') {
        // Model ran out of output tokens mid-generation — push what we have
        // and continue the loop so the model can pick up where it left off.
        logger.debug('max_tokens hit — continuing conversation');
        messages.push({ role: 'assistant', content: response.content });
        messages.push({ role: 'user', content: 'Continue from where you left off.' });
        continue;
      }

      const toolCallRequests: ToolCallRequest[] = toolUses.map(p => ({
        id: p.id ?? '',
        name: p.name ?? '',
        input: (p.input as Record<string, unknown>) ?? {},
      }));

      this.totalToolCalls += toolCallRequests.length;
      this.options.onToolCall?.(
        toolCallRequests.map(r => r.name).join(', '),
        toolCallRequests[0]?.input ?? {}
      );

      const toolResults = await this.executor.executeAll(toolCallRequests);

      for (const result of toolResults) {
        result.content = truncateToolOutput(result.content, this.maxToolOutputChars);

        this.options.onToolResult?.(
          toolCallRequests.find(r => r.id === result.toolUseId)?.name ?? '',
          result.content,
          result.isError
        );
      }

      messages.push({
        role: 'assistant',
        content: response.content,
      });

      messages.push({
        role: 'tool',
        content: toolResults.map(r => ({
          type: 'tool_result' as const,
          tool_use_id: r.toolUseId,
          content: r.content,
        })),
      });
    }

    if (this.iterationCount >= maxIterations && !finalResponse) {
      finalResponse = `Agent reached maximum iterations (${maxIterations}) without completing.`;
    }

    return this.buildResult(finalResponse, messages);
  }

  private buildResult(finalResponse: string, messages: Message[]): AgentRunResult {
    return {
      finalResponse,
      toolCallCount: this.totalToolCalls,
      iterations: this.iterationCount,
      usage: {
        inputTokens: this.totalInputTokens,
        outputTokens: this.totalOutputTokens,
      },
      messages,
    };
  }

  private async reviewWithAuditors(
    finalResponse: string,
    messages: Message[],
  ): Promise<boolean> {
    if (this.options.onAuditorReview) {
      return this.options.onAuditorReview(
        this.options.userMessage,
        finalResponse,
        messages,
      );
    }

    const registry = AuditorRegistry.getActive();
    if (!registry || !registry.isEnabled()) {
      return true;
    }

    const runners = registry.getEnabledRunners(this.options.provider, this.options.tools);
    if (runners.length === 0) {
      return true;
    }

    logger.debug({ auditorCount: runners.length }, 'Running enabled auditors');

    const results = await Promise.all(
      runners.map(runner =>
        runner.run({
          userMessage: this.options.userMessage,
          proposedResponse: finalResponse,
          conversationHistory: messages,
        }),
      ),
    );

    await this.emitAuditorFindings(results);

    const gateDecision = AuditorRunner.evaluateGate(results, runners);
    if (!gateDecision.blocked) {
      return true;
    }

    return this.promptForAuditorGate(gateDecision.blockingAuditors);
  }

  private async emitAuditorFindings(results: AuditorResult[]): Promise<void> {
    const options = this.options as AuditorAwareAgentRunOptions;
    if (options.onAuditorFindings) {
      await options.onAuditorFindings(results);
      return;
    }

    for (const result of results) {
      if (result.findings.length === 0) {
        console.log(
          chalk.magenta(
            `[AUDITOR: ${result.auditorName}] Finding: ${result.transcript || 'No findings.'}`
          )
        );
        continue;
      }

      for (const finding of result.findings) {
        console.log(
          chalk.magenta(
            `[AUDITOR: ${result.auditorName}] Finding: (${finding.severity}) ${finding.finding}`
          )
        );
      }
    }
  }

  private async promptForAuditorGate(results: AuditorResult[]): Promise<boolean> {
    const options = this.options as AuditorAwareAgentRunOptions;
    if (options.onAuditorGate) {
      return options.onAuditorGate(results);
    }

    const blockingSummary = results
      .filter(result => result.findings.length > 0)
      .map(result => `${result.auditorName}:${result.severity}`)
      .join(', ');

    console.log(
      chalk.magenta(
        `Auditor gate triggered. Findings at or above threshold: ${blockingSummary}`
      )
    );

    const decision = await prompts({
      type: 'select',
      name: 'action',
      message: 'Proceed with the proposed response?',
      choices: [
        { title: 'Proceed', value: 'proceed' },
        { title: 'Reject', value: 'reject' },
      ],
      initial: 1,
    });

    return decision.action === 'proceed';
  }
}

import chalk from 'chalk';
import prompts from 'prompts';
import type { Message } from '../providers/types.js';
import type { ToolCallRequest } from '../tools/types.js';
import type { AgentRunOptions, AgentRunResult } from './types.js';
import type { AuditorResult } from '../auditors/types.js';
import { AuditorRegistry } from '../auditors/AuditorRegistry.js';
import { AuditorRunner } from '../auditors/AuditorRunner.js';
import { Executor } from './Executor.js';
import { compressHistory } from '../context/MemoryCompressor.js';
import { logger } from '../utils/logger.js';

const DEFAULT_MAX_TOOL_OUTPUT_CHARS = 32_768;
const DEFAULT_AUTO_COMPRESS_AT = 80_000;
const DEFAULT_MAX_OUTPUT_TOKENS = 16_384;

interface AuditorAwareAgentRunOptions extends AgentRunOptions {
  onAuditorFindings?: (results: AuditorResult[]) => void | Promise<void>;
  onAuditorGate?: (results: AuditorResult[]) => Promise<boolean>;
}

/**
 * AgentRunner executes the ReAct agent loop.
 *
 * Remote constraints should be loaded before session start and injected into the
 * system prompt via ContextBuilder. See ConstraintLoader for fetching constraints
 * from the backend at GET /v1/projects/{id}/constraints.
 */

function estimateTokens(messages: Message[]): number {
  let chars = 0;
  for (const m of messages) {
    if (typeof m.content === 'string') {
      chars += m.content.length;
    } else {
      chars += JSON.stringify(m.content).length;
    }
  }
  return Math.ceil(chars / 4);
}

function truncateToolOutput(content: string, limit: number): string {
  if (content.length <= limit) return content;
  const kept = content.slice(0, limit);
  const droppedChars = content.length - limit;
  return `${kept}\n\n[truncated — showing first ${limit.toLocaleString()} of ${content.length.toLocaleString()} chars (${droppedChars.toLocaleString()} dropped)]`;
}

export class AgentRunner {
  private executor: Executor;
  private iterationCount = 0;
  private totalInputTokens = 0;
  private totalOutputTokens = 0;
  private totalToolCalls = 0;
  private maxToolOutputChars: number;

  constructor(private options: AgentRunOptions) {
    this.executor = new Executor({
      tools: options.tools,
      dangerousSkipApproval: options.dangerousSkipApproval ?? false,
      maxConcurrency: 3,
    });
    this.maxToolOutputChars = options.maxToolOutputChars ?? DEFAULT_MAX_TOOL_OUTPUT_CHARS;
  }

  async run(): Promise<AgentRunResult> {
    const maxIterations = this.options.maxIterations ?? 20;
    const autoCompressAt = this.options.autoCompressAt ?? DEFAULT_AUTO_COMPRESS_AT;
    const modelUserMessage = this.options.modelUserMessage ?? this.options.userMessage;

    let messages: Message[] = [
      ...(this.options.history ?? []),
      { role: 'user', content: this.options.userMessage },
    ];
    let modelMessages: Message[] = [
      ...(this.options.history ?? []),
      { role: 'user', content: modelUserMessage },
    ];

    let finalResponse = '';

    while (this.iterationCount < maxIterations) {
      this.iterationCount++;
      this.options.onIterationStart?.(this.iterationCount);

      logger.debug({ iteration: this.iterationCount }, 'Agent iteration');

      // Auto-compress if history has grown past threshold
      if (estimateTokens(modelMessages) > autoCompressAt && modelMessages.length > 6) {
        try {
          logger.debug('Auto-compressing conversation history');
          modelMessages = await compressHistory(
            modelMessages,
            this.options.provider,
            this.options.model,
          );
        } catch {
          logger.warn('Auto-compression failed, continuing with full history');
        }
      }

      let accumulatedText = '';

      const response = await this.options.provider.stream(
        {
          messages: modelMessages,
          systemPrompt: this.options.systemPrompt,
          tools: this.options.tools.map(t => t.definition),
          model: this.options.model,
          stream: true,
          maxTokens: this.options.maxOutputTokens ?? DEFAULT_MAX_OUTPUT_TOKENS,
        },
        delta => {
          if (delta.type === 'text_delta') {
            this.options.onTextDelta?.(delta.text);
            accumulatedText += delta.text;
          }
        }
      );

      this.totalInputTokens += response.usage.inputTokens;
      this.totalOutputTokens += response.usage.outputTokens;

      // Budget enforcement — check after every LLM response
      if (this.options.budgetGuard) {
        const check = this.options.budgetGuard.recordUsage(
          response.usage.inputTokens,
          response.usage.outputTokens,
        );
        if (check.action !== 'ok') {
          this.options.onBudgetCheck?.(check);
        }
        if (check.action === 'pause') {
          // Hard stop — append what we have and return immediately
          messages.push({ role: 'assistant', content: response.content });
          modelMessages.push({ role: 'assistant', content: response.content });
          return this.buildResult(
            response.content.filter(p => p.type === 'text').map(p => p.text ?? '').join('') || check.message,
            messages,
          );
        }
      }

      const toolUses = response.content.filter(p => p.type === 'tool_use');
      const textParts = response.content.filter(p => p.type === 'text');

      if (textParts.length > 0 || accumulatedText) {
        finalResponse = textParts.map(p => p.text ?? '').join('') || accumulatedText;
      }

      if (response.stopReason === 'end_turn' || toolUses.length === 0) {
        // Append the final assistant message so messages array is complete
        messages.push({ role: 'assistant', content: response.content });
        modelMessages.push({ role: 'assistant', content: response.content });

        if (finalResponse) {
          const shouldProceed = await this.reviewWithAuditors(finalResponse, modelMessages);
          if (!shouldProceed) {
            return this.buildResult('[Response blocked by auditor review]', messages);
          }
        }

        break;
      }

      if (response.stopReason === 'max_tokens') {
        // Model ran out of output tokens mid-generation — push what we have
        // and continue the loop so the model can pick up where it left off.
        logger.debug('max_tokens hit — continuing conversation');
        messages.push({ role: 'assistant', content: response.content });
        modelMessages.push({ role: 'assistant', content: response.content });
        messages.push({ role: 'user', content: 'Continue from where you left off.' });
        modelMessages.push({ role: 'user', content: 'Continue from where you left off.' });
        continue;
      }

      const toolCallRequests: ToolCallRequest[] = toolUses.map(p => ({
        id: p.id ?? '',
        name: p.name ?? '',
        input: (p.input as Record<string, unknown>) ?? {},
      }));

      this.totalToolCalls += toolCallRequests.length;
      this.options.onToolCall?.(
        toolCallRequests.map(r => r.name).join(', '),
        toolCallRequests[0]?.input ?? {}
      );

      const toolResults = await this.executor.executeAll(toolCallRequests);

      for (const result of toolResults) {
        result.content = truncateToolOutput(result.content, this.maxToolOutputChars);

        this.options.onToolResult?.(
          toolCallRequests.find(r => r.id === result.toolUseId)?.name ?? '',
          result.content,
          result.isError
        );
      }

      messages.push({
        role: 'assistant',
        content: response.content,
      });
      modelMessages.push({
        role: 'assistant',
        content: response.content,
      });

      messages.push({
        role: 'tool',
        content: toolResults.map(r => ({
          type: 'tool_result' as const,
          tool_use_id: r.toolUseId,
          content: r.content,
        })),
      });
      modelMessages.push({
        role: 'tool',
        content: toolResults.map(r => ({
          type: 'tool_result' as const,
          tool_use_id: r.toolUseId,
          content: r.content,
        })),
      });
    }

    if (this.iterationCount >= maxIterations && !finalResponse) {
      finalResponse = `Agent reached maximum iterations (${maxIterations}) without completing.`;
    }

    return this.buildResult(finalResponse, messages);
  }

  private buildResult(finalResponse: string, messages: Message[]): AgentRunResult {
    return {
      finalResponse,
      toolCallCount: this.totalToolCalls,
      iterations: this.iterationCount,
      usage: {
        inputTokens: this.totalInputTokens,
        outputTokens: this.totalOutputTokens,
      },
      messages,
    };
  }

  private async reviewWithAuditors(
    finalResponse: string,
    messages: Message[],
  ): Promise<boolean> {
    if (this.options.onAuditorReview) {
      return this.options.onAuditorReview(
        this.options.modelUserMessage ?? this.options.userMessage,
        finalResponse,
        messages,
      );
    }

    const registry = AuditorRegistry.getActive();
    if (!registry || !registry.isEnabled()) {
      return true;
    }

    const runners = registry.getEnabledRunners(this.options.provider, this.options.tools);
    if (runners.length === 0) {
      return true;
    }

    logger.debug({ auditorCount: runners.length }, 'Running enabled auditors');

    const results = await Promise.all(
      runners.map(runner =>
        runner.run({
          userMessage: this.options.modelUserMessage ?? this.options.userMessage,
          proposedResponse: finalResponse,
          conversationHistory: messages,
        }),
      ),
    );

    await this.emitAuditorFindings(results);

    const gateDecision = AuditorRunner.evaluateGate(results, runners);
    if (!gateDecision.blocked) {
      return true;
    }

    return this.promptForAuditorGate(gateDecision.blockingAuditors);
  }

  private async emitAuditorFindings(results: AuditorResult[]): Promise<void> {
    const options = this.options as AuditorAwareAgentRunOptions;
    if (options.onAuditorFindings) {
      await options.onAuditorFindings(results);
      return;
    }

    for (const result of results) {
      if (result.findings.length === 0) {
        console.log(
          chalk.magenta(
            `[AUDITOR: ${result.auditorName}] Finding: ${result.transcript || 'No findings.'}`
          )
        );
        continue;
      }

      for (const finding of result.findings) {
        console.log(
          chalk.magenta(
            `[AUDITOR: ${result.auditorName}] Finding: (${finding.severity}) ${finding.finding}`
          )
        );
      }
    }
  }

  private async promptForAuditorGate(results: AuditorResult[]): Promise<boolean> {
    const options = this.options as AuditorAwareAgentRunOptions;
    if (options.onAuditorGate) {
      return options.onAuditorGate(results);
    }

    const blockingSummary = results
